mapper.insert:
merge into sys_notice_read a using (
select #{noticeId} as notice_id, #{userId} as user_id from dual
) b on (a.notice_id = b.notice_id AND a.user_id = b.user_id) when not matched then insert (read_id, notice_id, user_id, read_time) values (seq_sys_notice_read.nextval, b.notice_id, b.user_id, sysdate)

mapper.select:
select u.user_id as userId, u.user_name as userName, u.nick_name as nickName, d.dept_name as deptName, u.phonenumber as phonenumber, r.read_time as readTime from sys_notice_read r inner join sys_user u on u.user_id = r.user_id and u.del_flag = '0' left join sys_dept d on d.dept_id = u.dept_id where r.notice_id = #{noticeId}
and ( u.user_name like concat(concat('%',#{searchValue}),'%') or u.nick_name like concat(concat('%',#{searchValue}),'%') )
order by r.read_time desc
